module top_module(
    input [3:0] _inv_A, B, C, D,
    output reg EQ, GT
);always @(*) begin
        if (_inv_A == B && C == D) begin
            EQ = 1'b1;
            GT = 1'b0;
        end else if (_inv_A > B || (_inv_A == B && C > D)) begin
            EQ = 1'b0;
            GT = 1'b1;
        end else begin
            EQ = 1'b0;
            GT = 1'b0;
        end
    end

endmodule
